INSERT INTO `content_manager` (`categories_id`, `parent_id`, `group_ids`, `languages_id`, `content_name`, `content_title`, `content_heading`, `content_text`, `sort_order`, `file_flag`, `content_file`, `download_file`, `content_status`, `content_group`, `content_delete`, `gm_link`, `gm_link_target`, `gm_priority`, `gm_changefreq`, `gm_sitemap_entry`, `gm_robots_entry`, `gm_url_keywords`, `protected`, `content_position`, `content_type`, `contents_meta_title`, `contents_meta_description`, `contents_meta_keywords`) VALUES
	(0, 0, '', 1, 'Session interrupted (PayPal)', 'Loss of session', 'Your session has been interrupted', 'For PayPal payments to work as expected it is essential that your browser sends a session identification (session cookie) when returning from PayPal authorization. Your browser did not send this identification, therefore your shopping session has been terminated. Please deactivate any &ldquo;anti virus&rdquo; or &ldquo;internet security&ldquo; software you may be running on your computer. Afterwards, you can log in to the shop system again and continue your shopping experience.<br />\r\n&nbsp;', 0, 0, '', '', 1, 3300001, 1, '', '', '0.0', 'always', 0, 1, 'session-lost', '1', 'pages_info', 'content', '', '', ''),
	(0, 0, '', 2, 'Sitzungsunterbrechung (PayPal)', 'Sitzung unterbrochen', 'Die Sitzung wurde unterbrochen', 'F&uuml;r das korrekte Funktionieren der Zahlung &uuml;ber PayPal ist es notwendig, dass Ihr Browser bei der R&uuml;ckkehr in den Shop nach der PayPal-Autorisierung weiterhin die Kennung der zuvor verwendeten Sitzung (Session-Cookie) sendet. Dies erfolgt gegenw&auml;rtig nicht. Ein m&ouml;glicher Grund k&ouml;nnte die Verwendung von &bdquo;Antiviren&ldquo;-Software oder sonstiger &bdquo;Internet Security&ldquo;-Software sein. Bitte deaktivieren Sie daher derlei Einflussfaktoren. Anschlie&szlig;end k&ouml;nnen Sie sich erneut in den Shop einloggen und Ihren Einkauf fortsetzen.<br />\r\n&nbsp;', 0, 0, '', '', 1, 3300001, 1, '', '', '0.0', 'always', 0, 1, 'session-lost', '1', 'pages_info', 'content', '', '', '');
INSERT INTO `content_manager` (`categories_id`, `parent_id`, `group_ids`, `languages_id`, `content_name`, `content_title`, `content_heading`, `content_text`, `sort_order`, `file_flag`, `content_file`, `download_file`, `content_status`, `content_group`, `content_delete`, `gm_link`, `gm_link_target`, `gm_priority`, `gm_changefreq`, `gm_last_modified`, `gm_sitemap_entry`, `gm_robots_entry`, `gm_url_keywords`, `protected`, `content_position`, `content_type`,`contents_meta_title`,`contents_meta_description`,`contents_meta_keywords`) VALUES
	(0, 0, '', 1, 'Privacy Notice', 'Privacy Notice', 'Privacy Notice', '<p>Enter your Privacy Notice information here.</p>', 0, 1, '', '', 1, 2, 0, '', '_blank', '0.0', 'weekly', '2008-08-25 17:21:28', 0, 1, 'privacy-notice', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'General Terms & Conditions', 'General Terms & Conditions', 'General Terms & Conditions', '<p>The General Terms & Conditions (GTC) of a webshop provide the legal framework for all transactions, they are pre-formulated contract terms on the part of the shop-owner. Faulty GTC however, can prove to be hazardous for online merchants, as invalid or outdated clauses within the conditions are a frequent cause for cease-and-decist orders. And keeping the GTC up to date can be time-consuming and work-intensive.</p><p>We therefore recommend to implement the services of our legal partners, that offer to automatically update the important legal texts in your shop to keep you safe from any cease-and-decists:</p><p><a style="color: #0000EE;" href="https://www.it-recht-kanzlei.de/Service/gambio-agb-schnittstelle.php" title="GTC for Gambio-Shops by IT-Recht-Kanzlei" target="_blank">GTC for Gambio-Shops by IT-Recht-Kanzlei</a></p><p><a style="color: #0000EE;" href="http://www.janolaw.de/partner/gambio/index.html?partnerid=8604#menu" title="GTC for Gambio-Shops by Janolaw" target="_blank">GTC for Gambio-Shops by Janolaw</a></p><p>That way you can lean back and concentrate your efforts on what really counts: Your customers</p>', 0, 1, '', '', 1, 3, 0, '', '_blank', '0.0', 'weekly', '2008-08-25 17:21:47', 0, 1, 'conditions-of-use', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'Legal Information', 'Legal Information', 'Legal Information', '<p>This is the place for your legal information. Every webshop is required by law to display its complete legal information to allow customers quick and easy access to all the relevant data of the shop-owner, including name, address or contact info.</p><p>If you are unsure about the exact elements required in your legal information and how to correctly display them, we recommend to make use of the services of our legal partners. They offer quick and straighforward ways to compile professional legal information for your shop. You can also choose to have all the legal texts in your shop automatically updated for you by our partners, so that they are always kept in line with current jurisdiction.</p><p><a style="color: #0000EE;" href="https://www.it-recht-kanzlei.de/Service/gambio-agb-schnittstelle.php" title="Service for legal information by IT-Recht-Kanzlei" target="_blank">Service for legal information by IT-Recht-Kanzlei</a><p><p><a style="color: #0000EE;" href="http://www.janolaw.de/partner/gambio/index.html?partnerid=8604#menu" title="Service for legal information by Janolaw" target="_blank">Service for legal information by Janolaw</a></p>', 0, 1, '', '', 1, 4, 0, '', '_blank', '0.0', 'weekly', '2008-08-25 17:22:50', 0, 1, 'imprint', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'Index', 'Index', 'Welcome', '<h1>Welcome to your Shop</h1>\r\n<p>This Onlineshop was created with <a href="https://www.gambio.de"><strong>Gambio Shopsoftware</strong></a>.</p>\r\n<p>This text can be edited at Content Manager -&gt; Index in the backend.</p>', 0, 4, '', '', 1, 5, 0, '', '_blank', '0.0', 'always', '2011-03-16 16:28:26', 1, 0, '', 1, 'elements_start', 'content','','',''),
	(0, 0, '', 2, 'Privatsphäre und Datenschutz', 'Privatsphäre und Datenschutz', 'Privatsphäre und Datenschutz', '<p>F&uuml;ge hier deine Informationen &uuml;ber Privatsph&auml;re und Datenschutz ein. Alternativ kannst du das Plugin <i>janolaw AGB-Hosting</i> nutzen und deine Datenschutzerkl&auml;rung mithilfe eines Online-Assistenten direkt zusammen mit AGB, Widerrufsbelehrung und Impressum erstellen. In nur wenigen Minuten hast du&nbsp;unter fachkundiger Anleitung die <strong>wichtigsten</strong> Dokumente f&uuml;r deinen Shop <strong>individuell</strong> zusammengestellt.</p><p>Das Plugin sorgt&nbsp;daf&uuml;r, dass die Dokumente in deinen Shop eingebunden und bei ver&auml;nderter Rechtslage <strong>automatisch aktualisiert</strong> werden. Dabei wird die aktuelle Widerrufsbelehrung zus&auml;tzlich auch in der <strong>E-Mail-Best&auml;tigung</strong> angezeigt, die du an deine Kunden verschickst. Zusammen mit&nbsp;der <strong>Abmahnkostenhaftung</strong> durch die janolaw AG bist du damit optimal vor Abmahnungen gesch&uuml;tzt. <a href="http://www.janolaw.de/internetrecht/agb/agb-hosting-service/gambio/?partnerid=8604#menu">Hier</a> kannst du den Service unseres Partners janolaw buchen.</p>', 3, 1, '', '', 1, 2, 0, '', '_blank', '0.0', 'weekly', '2008-08-26 19:59:30', 0, 1, 'privatsphaere-und-datenschutz', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 2, 'AGB', 'AGB', 'Allgemeine Geschäftsbedingungen', '<p>Die Allgemeinen Gesch&auml;ftsbedingungen (AGB) eines Onlineshops bilden den rechtlichen Rahmen f&uuml;r alle Gesch&auml;fte, sie sind vorformulierte Vertragsbedingungen seitens des Shopbetreibers. Fehlerhafte AGB sind aber auch immer wieder ein Stolperstein f&uuml;r Onlineh&auml;ndler, denn gerade ung&uuml;ltige oder veraltete Klauseln in den Gesch&auml;ftsbedingungen sind ein h&auml;ufiger Grund f&uuml;r Abmahnungen. Die eigenen AGB immer auf dem neuesten Stand zu halten kann zeitaufw&auml;ndig und arbeitsintensiv sein.</p><p>Wir empfehlen unseren Kunden, die AGB-Services unserer Rechtspartner in Anspruch zu nehmen, mit denen die wichtigsten Rechtstexte in deinem Shop automatisch aktualisiert werden und du keine Angst vor Abmahnungen haben musst:</p><p><a style="color: #0000EE;" href="https://www.it-recht-kanzlei.de/Service/gambio-agb-schnittstelle.php" title="AGB f&uuml;r Gambio-Shops von der IT-Recht-Kanzlei" target="_blank">AGB f&uuml;r Gambio-Shops von der IT-Recht-Kanzlei</a></p><p><a style="color: #0000EE;" href="http://www.janolaw.de/partner/gambio/index.html?partnerid=8604#menu" title="AGB f&uuml;r Gambio-Shops von Janolaw" target="_blank">AGB f&uuml;r Gambio-Shops von Janolaw</a></p><p>So kannst du dich zur&uuml;cklehnen und auf das Wesentliche konzentrieren: Deine Kunden.</p>', 1, 1, '', '', 1, 3, 0, '', '_blank', '0.0', 'weekly', '2012-01-30 14:45:57', 0, 1, 'allgemeine-geschaeftsbedingungen', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 2, 'Suchen', 'Suchen', '', '', 0, 3, '', '', 0, 30, 1, 'advanced_search.php', '_top', '0.0', 'always', '2008-07-30 04:24:06', 0, 0, '', 0, 'pages_main', 'link','','',''),
	(0, 0, '', 1, 'Search', 'Search', '', '', 0, 3, '', '', 0, 30, 1, 'advanced_search.php', '_top', '0.0', 'always', '2008-07-30 04:24:06', 0, 0, '', 0, 'pages_main', 'link','','',''),
	(0, 0, '', 2, 'Impressum', 'Impressum', 'Impressum', '<p>An dieser Stelle kannst du dein Impressum hinterlegen. Ein vollst&auml;ndiges Impressum ist f&uuml;r jeden Onlineshop rechtlich vorgeschrieben, es dient dazu, Kunden schnell und einfach Zugang zu den relevanten Informationen des Shopbetreibers zu erlauben. Dazu z&auml;hlen Name, Anschrift oder Kontaktdaten.</p><p>Wenn du dir nicht ganz sicher bist, welche Elemente in ein rechtssicheres Impressum geh&ouml;ren und wie diese genau dargestellt werden m&uuml;ssen, empfehlen wir dir, die Dienste unserer Rechtspartner in Anspruch zu nehmen. Damit kannst du dir schnell und unkompliziert ein professionelles Impressum f&uuml;r deinen Shop erstellen lassen, das sogar zusammen mit allen anderen Rechtstexten im Shop durch unsere Partner immer auf dem neuesten Stand der Rechtsprechung gehalten werden kann:</p><p><a style="color: #0000EE;" href="https://www.it-recht-kanzlei.de/Service/gambio-agb-schnittstelle.php" title="Impressumsservice der IT-Recht-Kanzlei" target="_blank">Impressumsservice der IT-Recht-Kanzlei</a></p><p><a style="color: #0000EE;" href="http://www.janolaw.de/partner/gambio/index.html?partnerid=8604#menu" title="Impressumsservice von Janolaw" target="_blank">Impressumsservice von Janolaw</a></p>', 0, 1, '', '', 1, 4, 0, '', '_top',   '0.0', 'weekly', '2008-07-29 18:01:46', 0, 1, 'impressum', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 2, 'Index', 'Index', 'Willkommen', '<h1>Herzlich willkommen in deinem Shop</h1>\r\n<p>Dieser Onlineshop wurde mit der <a href="https://www.gambio.de"><strong>Gambio Shopsoftware</strong></a> erstellt.</p>\r\n<p>Diesen Text kannst du im Gambio Admin unter Content Manager -&gt; Index bearbeiten.</p>', 0, 4, '', '', 1, 5, 0, '', '_blank', '0.0', 'always', '2011-03-16 16:24:27', 1, 0, '', 1, 'elements_start', 'content','','','');
INSERT INTO `content_manager` (`categories_id`, `parent_id`, `group_ids`, `languages_id`, `content_name`, `content_title`, `content_heading`, `content_text`, `sort_order`, `file_flag`, `content_file`, `download_file`, `content_status`, `content_group`, `content_delete`, `gm_link`, `gm_link_target`, `gm_priority`, `gm_changefreq`, `gm_sitemap_entry`, `gm_robots_entry`, `gm_url_keywords`, `protected`, `content_position`, `content_type`,`contents_meta_title`,`contents_meta_description`,`contents_meta_keywords`) VALUES
	(0, 0, '', 2, 'Gutscheine', 'Gutscheine', 'Gutscheine - Fragen und Antworten', '<table cellSpacing=0 cellPadding=0>\r\n<tbody>\r\n<tr>\r\n<td class=main><STRONG>Gutscheine kaufen </STRONG></td></tr>\r\n<tr>\r\n<td class=main>Gutscheine können, falls sie im Shop angeboten werden, wie normale Artikel gekauft werden. Sobald du einen Gutschein gekauft hast und dieser nach erfolgreicher Zahlung freigeschaltet wurde, erscheint der Betrag unter deinem Warenkorb. Nun kannst du über den Link " Gutschein versenden " den gewünschten Betrag per E-Mail versenden. </td></tr></tbody></table>\r\n<table cellSpacing=0 cellPadding=0>\r\n<tbody>\r\n<tr>\r\n<td class=main><STRONG>Wie man Gutscheine versendet </STRONG></td></tr>\r\n<tr>\r\n<td class=main>Um einen Gutschein zu versenden, klicke bitte auf den Link "Gutschein versenden" in deinem Einkaufskorb. Um einen Gutschein zu versenden, benötigen wir folgende Angaben von deinen: Vor- und Nachname des Empfängers. Eine gültige E-Mail Adresse des Empfängers. Den gewünschten Betrag (Du kannst auch Teilbeträge deines Guthabens versenden). Eine kurze Nachricht an den Empfänger. Bitte überprüfe deine Angaben noch einmal vor dem Versenden. Du hast vor dem Versenden jederzeit die Möglichkeit deine Angaben zu korrigieren. </td></tr></tbody></table>\r\n<table cellSpacing=0 cellPadding=0>\r\n<tbody>\r\n<tr>\r\n<td class=main><STRONG>Mit Gutscheinen Einkaufen. </STRONG></td></tr>\r\n<tr>\r\n<td class=main>Sobald du über ein Guthaben verfügst, kannst du dieses zum Bezahlen deiner Bestellung verwenden. Während des Bestellvorganges hast du die Möglichkeit dein Guthaben einzulösen. Falls das Guthaben unter dem Warenwert liegt musst du deine bevorzugte Zahlungsweise für den Differenzbetrag wählen. Übersteigt dein Guthaben den Warenwert, steht deinen das Restguthaben selbstverständlich für deine nächste Bestellung zur Verfügung. </td></tr></tbody></table>\r\n<table cellSpacing=0 cellPadding=0>\r\n<tbody>\r\n<tr>\r\n<td class=main><STRONG>Gutscheine verbuchen. </STRONG></td></tr>\r\n<tr>\r\n<td class=main>Wenn du einen Gutschein per E-Mail erhalten hast, kannst du den Betrag wie folgt verbuchen:. <br />1. Klicke auf den in der E-Mail angegebenen Link. Falls du noch nicht über ein persönliches Kundenkonto verfügst, hast du die Möglichkeit ein Konto zu eröffnen. <br />2. Nachdem du ein Produkt in den Warenkorb gelegt hast, kann du dort deinen Gutscheincode eingeben.</td></tr></tbody></table>\r\n<table cellSpacing=0 cellPadding=0>\r\n<tbody>\r\n<tr>\r\n<td class=main><STRONG>Falls es zu Problemen komm sollte: </STRONG></td></tr>\r\n<tr>\r\n<td class=main>Falls es wider Erwarten zu Problemen mit einem Gutschein komm sollte, kontaktiere uns bitte per E-Mail : you@yourdomain.com. Bitte beschreibe möglichst genau das Problem, wichtige Angaben sind unter anderem: deine Kundennummer, der Gutscheincode, Fehlermeldungen des Systems sowie der von deinen benutzte Browser. </td></tr></tbody></table>', 0, 1, '', '', 0, 6, 0, '', '', '', '', 1, 0, '', 1, 'pages_info', 'content','','','');
