	(0, 0, '', 2, 'Über uns', 'Über uns', 'Über uns', '<p>F&uuml;ge hier deine Informationen &uuml;ber dich bzw. Dein Unternehmen ein.</p>', 1, 3, '', '', 0, 82, 1, '', '_blank', '0.0', 'always', '2008-08-25 17:57:47', 0, 0, '', 0, 'pages_main', 'content','','',''),
