	(0, 0, '', 2, 'Kontakt', 'Kontakt', 'Kontakt', '<p>F&uuml;ge hier deine Kontaktinformationen ein.</p>', 0, 1, '', '', 1, 7, 0, '', '_blank', '0.0', 'always', '2008-08-26 20:00:45', 1, 0, 'mein-kontakt', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'Contact', 'Contact', 'Contact', '<p>Enter your Contact information here.</p>', 0, 1, '', '', 1, 7, 0, '', '_blank', '0.0', 'always', '2008-08-25 17:23:42', 1, 0, 'contact', 1, 'pages_info', 'content','','','');
