	(0, 0, '', 1, 'Footer Header', 'Footer Header', '', '<p>This text can be edited at Content Manager -&gt; Elements -&gt; Footer -&gt; Footer Header in the backend.</p>', 0, 4, '', '', 1, 199, 0, '', '_blank', '0.0', 'always', '2011-03-17 11:39:53', 0, 0, '', 1, 'elements_footer', 'content','','',''),
	(0, 0, '', 2, 'Footer Kopfzeile', 'Footer Kopfzeile', '', '<p>Diesen Text kannst du im Gambio Admin unter Content Manager -&gt; Elemente -&gt; Footer -&gt; Footer Kopfzeile bearbeiten.</p>', 0, 4, '', '', 1, 199, 0, '', '_blank', '0.0', 'always', '2011-03-17 11:39:26', 0, 0, '', 1, 'elements_footer', 'content','','',''),
	(0, 0, '', 1, 'Checkout confirmation information', 'Checkout confirmation information', '', '', 0, 4, '', '', 1, 198, 0, '', '_blank', '0.0', 'always', '2011-03-17 11:39:53', 0, 0, '', 1, 'elements_others', 'content','','',''),
	(0, 0, '', 2, 'Bestellzusammenfassung Information', 'Bestellzusammenfassung Information', '', '', 0, 4, '', '', 1, 198, 0, '', '_blank', '0.0', 'always', '2011-03-17 11:39:26', 0, 0, '', 1, 'elements_others', 'content','','',''),
	(0, 0, '', 1, 'Shipping & payment conditions', 'Shipping & payment conditions', 'Shipping & payment conditions', 'Enter your information about shipping and payment conditions here. <br /><br />{$shipping_and_payment_matrix}<br /><br />{$klarna_hub_terms_and_conditions}<br />', 0, 1, '', '', 1, 3889891, 0, '', '_blank', '1.0', 'weekly', '2014-06-10 13:46:44', 0, 1, 'Shipping-and-payment-conditions', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 2, 'Versand- & Zahlungsbedingungen', 'Versand- & Zahlungsbedingungen', 'Versand- & Zahlungsbedingungen', 'F&uuml;ge hier deine Informationen zu Versand- &amp; Zahlungsbedingungen ein. <br /><br />{$shipping_and_payment_matrix}<br /><br />{$klarna_hub_terms_and_conditions}<br />', 0, 1, '', '', 1, 3889891, 0, '', '_blank', '1.0', 'weekly', '2014-06-10 13:46:44', 0, 1, 'Versand-und-Zahlungsbedingungen', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'Right of Withdrawal / Model Withdrawal Form', 'Right of Withdrawal / Model Withdrawal Form', 'Right of Withdrawal / Model Withdrawal Form', '<img alt="" src="public/theme/images/icon_arrow.gif" style="margin-bottom:2px" /> <a href="{$PAGE_URL}#withdrawal_rights"><u>Right of Withdrawal</u></a> <br />\r\n<br />\r\n<img alt="" src="public/theme/images/icon_arrow.gif" style="margin-bottom:2px" /> <a href="{$PAGE_URL}#withdrawal_form"><u>Model Withdrawal Form</u></a> <br />\r\n<br />\r\n<br />\r\n<h2><a name="withdrawal_rights"></a>Right of Withdrawal <span style="font-size: 13px; font-weight: normal;">(<a href="{$PDF_URL}"><u>Download as PDF</u></a>)</span></h2>\r\n<span>{$WITHDRAWAL_TEXT}</span><br />\r\n<br />\r\n<br />\r\n{* withdrawal_form_start *}\r\n<h2><a name="withdrawal_form"></a>Model Withdrawal Form</h2>\r\n{* withdrawal_pdf_link_start *}<span>Our model withdrawal form as PDF document: <a href="{$PDF_FORM_URL}"><u>DOWNLOAD</u></a></span><br />\r\n{* withdrawal_pdf_link_end *} {* withdrawal_form_link_start *}<span>Our online model withdrawal form: <a href="{$WEBFORM_URL}"><u>ONLINE-FORM</u></a></span><br />\r\n{* withdrawal_form_link_end *} <br />\r\n<br />\r\n{* withdrawal_form_end *}<span><em>To open the downloadable PDF-files, you need an additional program such as the Adobe Reader, which you can download online for free. The current version of the Adobe Reader you can find <a href="http://get.adobe.com/uk/reader/" target="_blank"><u>here</u></a>.</em></span><br />\r\n<br />', 0, 1, '', '', 1, 3889895, 0, '', '_blank', '1.0', 'weekly', '2008-08-26 20:02:53', 0, 1, 'Right-of-Withdrawal--Model-Withdrawal-Form', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 2, 'Widerrufsrecht & Muster-Widerrufsformular', 'Widerrufsrecht & Muster-Widerrufsformular', 'Widerrufsrecht & Muster-Widerrufsformular', '<img style="margin-bottom:2px" src="public/theme/images/icon_arrow.gif" alt="" /> <a href="{$PAGE_URL}#withdrawal_rights"><u>Widerrufsrecht</u></a> <br />\r\n<br />\r\n<img style="margin-bottom:2px" src="public/theme/images/icon_arrow.gif" alt="" /> <a href="{$PAGE_URL}#withdrawal_form"><u>Muster-Widerrufsformular</u></a> <br />\r\n<br />\r\n<br />\r\n<h2><a name="withdrawal_rights"></a>Widerrufsrecht <span style="font-size: 13px; font-weight: normal;">(<a href="{$PDF_URL}"><u>Als PDF downloaden</u></a>)</span></h2>\r\n<span>{$WITHDRAWAL_TEXT}</span><br />\r\n<br />\r\n<br />\r\n{* withdrawal_form_start *}\r\n<h2><a name="withdrawal_form"></a>Muster-Widerrufsformular</h2>\r\n{* withdrawal_pdf_link_start *}<span>Unser Muster-Widerrufsformular im PDF-Format: <a href="{$PDF_FORM_URL}"><u>DOWNLOAD</u></a></span><br />\r\n{* withdrawal_pdf_link_end *} {* withdrawal_form_link_start *}<span>Unser Muster-Widerrufsformular zum online Ausf&uuml;llen: <a href="{$WEBFORM_URL}"><u>ONLINE-FORMULAR</u></a></span><br />\r\n{* withdrawal_form_link_end *} <br />\r\n<br />\r\n{* withdrawal_form_end *}<span><em>Um die zum Download angebotenen PDF-Dateien zu &ouml;ffnen, ben&ouml;tigen Sie ein Zusatzprogramm, wie zum Beispiel den Adobe Reader, welchen Sie im Internet kostenfrei herunterladen k&ouml;nnen. Die aktuelle Version des Adobe Readers finden Sie <a href="http://get.adobe.com/de/reader/" target="_blank"><u>hier</u></a>.</em></span><br />\r\n<br />', 0, 1, '', '', 1, 3889895, 0, '', '_blank', '1.0', 'weekly', '2008-08-26 20:02:53', 0, 1, 'Widerrufsrecht-und-Muster-Widerrufsformular', 1, 'pages_info', 'content','','',''),
	(0, 0, '', 1, 'Withdrawal 1', 'Withdrawal 1', 'Withdrawal 1', '<p>Enter your Withdrawal information here.</p>', 1, 5, '', '', 1, 3889896, 0, '', '_blank', '1.0', 'never', '2014-07-03 12:12:50', 0, 0, '', '1', 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 1, 'Withdrawal 2', 'Withdrawal 2', 'Withdrawal 2', 'Withdrawal 2 content', 2, 5, '', '', 0, 3889897, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 1, 'Withdrawal 3', 'Withdrawal 3', 'Withdrawal 3', 'Withdrawal 3 content', 3, 5, '', '', 0, 3889898, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 1, 'Withdrawal 4', 'Withdrawal 4', 'Withdrawal 4', 'Withdrawal 4 content', 4, 5, '', '', 0, 3889899, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 2, 'Widerrufsrecht 1', 'Widerrufsrecht 1', 'Widerrufsrecht 1', '<p>F&uuml;ge hier deine Hinweise zum Widerrufsrecht ein. Alternativ kannst du das Plugin <em>janolaw AGB-Hosting</em> nutzen und deine Widerrufsbelehrung mithilfe eines Online-Assistenten direkt zusammen mit AGB, Datenschutzerkl&auml;rung und Impressum erstellen. In nur wenigen Minuten hast du&nbsp;unter fachkundiger Anleitung die <strong>wichtigsten</strong> Dokumente f&uuml;r deinen Shop <strong>individuell </strong>zusammengestellt.</p>\r\n\r\n<p>Das Plugin sorgt&nbsp;daf&uuml;r, dass die Dokumente in deinen Shop eingebunden und bei ver&auml;nderter Rechtslage <strong>automatisch aktualisiert</strong> werden. Dabei wird die aktuelle Widerrufsbelehrung zus&auml;tzlich auch in der <strong>E-Mail-Best&auml;tigung</strong> angezeigt, die du an deine Kunden verschicken. Zusammen mit der <strong>Abmahnkostenhaftung</strong> durch die janolaw AG bist du damit optimal vor Abmahnungen gesch&uuml;tzt. <a href="http://www.janolaw.de/internetrecht/agb/agb-hosting-service/gambio/?partnerid=8604#menu">Hier</a> kannst du den Service unseres Partners janolaw buchen.</p>', 1, 5, '', '', 1, 3889896, 0, '', '_blank', '1.0', 'never', '2014-07-03 12:11:43', 0, 0, '', '1', 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 2, 'Widerrufsrecht 2', 'Widerrufsrecht 2', 'Widerrufsrecht 2', 'Widerrufsrecht 2 Inhalt', 2, 5, '', '', 0, 3889897, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 2, 'Widerrufsrecht 3', 'Widerrufsrecht 3', 'Widerrufsrecht 3', 'Widerrufsrecht 3 Inhalt', 3, 5, '', '', 0, 3889898, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','',''),
	(0, 0, '', 2, 'Widerrufsrecht 4', 'Widerrufsrecht 4', 'Widerrufsrecht 4', 'Widerrufsrecht 4 Inhalt', 4, 5, '', '', 0, 3889899, 0, '', '_blank', '1.0', 'never', '2014-06-10 13:46:44', 0, 0, '', 1, 'elements_withdrawal', 'content','','','');
